#[tauri::command]
pub fn browser_snapshot(
    state: State<'_, BrowserBridgeState>,
    page_revision: Option<String>,
) -> Result<BrowserPageSnapshot, String> {
    let value = request_bridge_value(
        &state.inner,
        "snapshot",
        json!({ "pageRevision": page_revision }),
    )?;
    let snapshot: BrowserPageSnapshot =
        serde_json::from_value(value).map_err(|_| "浏览器快照协议无效".to_string())?;
    if let Ok(mut session) = state.inner.session.lock() {
        if let Some(current) = session.as_mut() {
            let tab_id = current.tab_id;
            if apply_snapshot(current, snapshot.clone(), tab_id).is_err() {
                return Err("浏览器页面来源已经变化，请重新配对当前标签页".into());
            }
        }
    }
    let snapshot = state
        .inner
        .session
        .lock()
        .ok()
        .and_then(|session| {
            session
                .as_ref()
                .and_then(|current| current.snapshot.clone())
        })
        .ok_or_else(|| "浏览器快照不可用".to_string())?;
    Ok(snapshot)
}

