    #[test]
    fn cancelling_a_pending_browser_request_wakes_without_waiting_for_timeout() {
        let state = init_browser_bridge_state();
        let inner = Arc::clone(&state.inner);
        let (sender, receiver) = mpsc::channel::<String>();
        if let Ok(mut session) = inner.session.lock() {
            let mut current = test_session("pending-cancel");
            current.outbound = Some(sender);
            *session = Some(current);
        }

        let pending = start_request_bridge(&inner, "submit", json!({})).expect("request starts");
        let request_id = receiver
            .recv_timeout(Duration::from_secs(1))
            .expect("request should be sent");
        assert!(request_id.contains("\"type\":\"request\""));

        let waiter_inner = Arc::clone(&inner);
        let waiter = thread::spawn(move || {
            wait_request_bridge(&waiter_inner, pending, Some("run-pending-cancel"))
        });
        cancel_browser_run(&inner, "run-pending-cancel").expect("cancellation should be recorded");
        let result = waiter.join().expect("waiter should finish");
        assert!(result.is_err_and(|error| error.contains("运行已取消")));
    }

    fn follow_redirect_fixture<R, F>(
        start: &str,
        resolver: R,
        mut fetch: F,
    ) -> Result<Url, WorkAssistantError>
    where
        R: Fn(&str, u16) -> Result<Vec<SocketAddr>, WorkAssistantError>,
        F: FnMut(&Url) -> Result<Option<String>, WorkAssistantError>,
    {
        let mut current =
            Url::parse(start).map_err(|_| WorkAssistantError::blocked("invalid fixture URL"))?;
        for redirect_index in 0..=MAX_REDIRECTS {
            let (validated, _) =
                resolve_public_url_with(&current.to_string(), |host, port| resolver(host, port))?;
            let Some(location) = fetch(&validated)? else {
                return Ok(validated);
            };
            if redirect_index == MAX_REDIRECTS {
                return Err(WorkAssistantError::blocked("网页重定向次数超过限制"));
            }
            current = validated
                .join(&location)
                .map_err(|_| WorkAssistantError::blocked("网页重定向地址无效"))?;
        }
        Err(WorkAssistantError::blocked("网页请求未完成"))
    }

    #[test]
    fn injected_redirect_fixture_rejects_private_target_before_second_fetch() {
        let public_address = SocketAddr::from(([93, 184, 216, 34], 443));
        let resolver = |host: &str, _port: u16| match host {
            "public.example.test" => Ok(vec![public_address]),
            "private.example.test" => Ok(vec![SocketAddr::from(([127, 0, 0, 1], 80))]),
            _ => Err(WorkAssistantError::blocked("unknown fixture host")),
        };
        let mut fetched = Vec::new();
        let result =
            follow_redirect_fixture("https://public.example.test/start", resolver, |url| {
                fetched.push(url.to_string());
                Ok(Some("http://private.example.test/admin".into()))
            });

        assert!(result.is_err());
        assert_eq!(fetched, vec!["https://public.example.test/start"]);
        assert!(
            resolve_public_url_with("https://private.example.test/admin", |_, _| Ok(vec![
                SocketAddr::from(([10, 0, 0, 8], 80))
            ]),)
            .is_err()
        );
    }

    #[test]
    fn redirect_targets_and_dns_results_that_resolve_to_private_addresses_are_blocked() {
        let base = Url::parse("https://example.com/start").unwrap();
        for location in [
            "http://127.0.0.1/admin",
            "http://169.254.169.254/latest/meta-data",
            "http://[::1]/admin",
        ] {
            let target = base.join(location).unwrap();
            assert!(validate_public_url(target.as_str()).is_err(), "{target}");
        }

        for address in [
            SocketAddr::from(([10, 0, 0, 7], 443)),
            SocketAddr::from(([192, 168, 1, 7], 443)),
            SocketAddr::from(([169, 254, 169, 254], 80)),
            SocketAddr::from(([127, 0, 0, 1], 443)),
            SocketAddr::from(([0, 0, 0, 0], 443)),
        ] {
            assert!(
                is_blocked_ip(address.ip()),
                "DNS result {address} must be blocked"
            );
        }
    }

    #[test]
    fn browser_action_audit_is_persisted_without_draft_or_token_values() {
        let directory =
            std::env::temp_dir().join(format!("papyrus-browser-audit-{}", Uuid::new_v4()));
        let state = WorkAssistantState {
            roots: std::sync::RwLock::new(Vec::new()),
            previews: Mutex::new(HashMap::new()),
            approvals: Mutex::new(HashMap::new()),
            cancelled_runs: Mutex::new(HashSet::new()),
            cancelled_execution_audits: Mutex::new(HashSet::new()),
            audit_path: directory.join("audit.jsonl"),
            audit_guard: Mutex::new(()),
        };
        let preview = BrowserActionPreview {
            id: "preview-1".into(),
            revision: "revision".into(),
            action: "fillDraft".into(),
            action_hash: "hash".into(),
            risk: "reversible".into(),
            title: "填写草稿".into(),
            target_summary: "https://example.com".into(),
            impact_summary: "普通文本".into(),
            reversible: true,
            expires_at: unix_seconds().saturating_add(60),
            origin: "https://example.com".into(),
            page_title: "Example".into(),
            element_name: Some("Title".into()),
        };
        let response = BrowserActionResponse {
            ok: true,
            summary: "server must not enter the audit record: secret draft".into(),
            data: None,
            error_code: None,
            recoverable: None,
        };

        append_browser_action_audit(&state, &preview, "fillDraft", Ok(&response));
        let entries = crate::work_assistant::read_audit_entries(&state.audit_path).unwrap();
        assert_eq!(entries.len(), 1);
        assert_eq!(entries[0].event, "browser_action_completed");
        assert!(entries[0].detail.contains("action=fillDraft"));
        assert!(!entries[0].detail.contains("secret draft"));
        assert!(!entries[0].detail.contains("hash"));
        std::fs::remove_dir_all(directory).unwrap();
    }

