    #[test]
    fn browser_action_state_cleanup_removes_expired_entries_and_caps_maps() {
        let state = init_browser_bridge_state();
        let inner = Arc::clone(&state.inner);
        let now = unix_seconds();
        let request = BrowserActionRequest {
            element_token: None,
            value: None,
            page_revision: String::new(),
            snapshot_id: None,
            url: Some("https://example.com".into()),
            directory_root_id: None,
            target_href: None,
            href_fingerprint: None,
        };

        if let Ok(mut previews) = inner.browser_previews.lock() {
            previews.insert(
                "expired".into(),
                StoredBrowserPreview {
                    preview: BrowserActionPreview {
                        id: "expired".into(),
                        revision: String::new(),
                        action: "navigate".into(),
                        action_hash: "hash".into(),
                        risk: "reversible".into(),
                        title: "expired".into(),
                        target_summary: String::new(),
                        impact_summary: String::new(),
                        reversible: true,
                        expires_at: now.saturating_sub(1),
                        origin: "https://example.com".into(),
                        page_title: String::new(),
                        element_name: None,
                    },
                    session_id: "session".into(),
                    run_id: "run".into(),
                    tool_call_id: "tool".into(),
                    action: "navigate".into(),
                    request: request.clone(),
                    navigation_generation: 0,
                },
            );
            for index in 0..(MAX_BROWSER_PREVIEWS + 8) {
                let id = format!("preview-{index}");
                previews.insert(
                    id.clone(),
                    StoredBrowserPreview {
                        preview: BrowserActionPreview {
                            id,
                            revision: String::new(),
                            action: "navigate".into(),
                            action_hash: "hash".into(),
                            risk: "reversible".into(),
                            title: String::new(),
                            target_summary: String::new(),
                            impact_summary: String::new(),
                            reversible: true,
                            expires_at: now.saturating_add(index as u64 + 1),
                            origin: "https://example.com".into(),
                            page_title: String::new(),
                            element_name: None,
                        },
                        session_id: "session".into(),
                        run_id: "run".into(),
                        tool_call_id: "tool".into(),
                        action: "navigate".into(),
                        request: request.clone(),
                        navigation_generation: 0,
                    },
                );
            }
        }

        if let Ok(mut approvals) = inner.browser_approvals.lock() {
            for index in 0..(MAX_BROWSER_APPROVALS + 8) {
                let token = format!("approval-{index}");
                approvals.insert(
                    token.clone(),
                    StoredBrowserApproval {
                        token: token.clone(),
                        preview_id: "preview".into(),
                        run_id: "run".into(),
                        action_hash: "hash".into(),
                        expires_at: now.saturating_add(index as u64 + 1),
                    },
                );
            }
        }

        cleanup_browser_action_state(&inner);

        let previews = inner.browser_previews.lock().unwrap();
        assert!(!previews.contains_key("expired"));
        assert!(previews.len() <= MAX_BROWSER_PREVIEWS);
        drop(previews);
        let approvals = inner.browser_approvals.lock().unwrap();
        assert!(approvals.len() <= MAX_BROWSER_APPROVALS);
    }

