// Keep these imports intentionally used by the loopback protocol on all desktop targets; they
// also make it explicit that the bridge never binds anything other than a loopback TCP socket.
#[allow(dead_code)]
fn _loopback_only(_: SocketAddr, _: &mut TcpStream) {}
